#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=55;
int n,a[N][N],s[N][N],ans;
unordered_map<int,int> mp;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			cin>>a[i][j];
			s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+a[i][j];
		}
	}
	for(int x=1;x<=n;x++)
	{
		for(int y=1;y<=n;y++)
		{
			for(int x2=1;x2<=x;x2++)
			{
				for(int y2=1;y2<=y;y2++)
				{
					mp[s[x][y]-s[x][y2-1]-s[x2-1][y]+s[x2-1][y2-1]]++;
				}
			}
			for(int x2=x;x2<=n;x2++)
			{
				for(int y2=y;y2<=n;y2++)
				{
					int tmp=s[x2][y2]-s[x2][y]-s[x][y2]+s[x][y];
					if(mp.count(tmp)) ans+=mp[tmp]; 
				}
			}
			mp.clear();
			for(int x2=x;x2<=n;x2++)
			{
				for(int y2=1;y2<=y;y2++)
				{
					// 右下：x2 y 左上：x y2 
					mp[s[x2][y]-s[x2][y2-1]-s[x-1][y]+s[x-1][y2-1]]++;
				}
			}
			for(int x2=1;x2<=x;x2++)
			{
				for(int y2=y;y2<=n;y2++)
				{
					// 右下：x-1 y2  左上：x2 y+1
					int tmp=s[x-1][y2]-s[x-1][y]-s[x2-1][y2]+s[x2-1][y];
					if(mp.count(tmp)) ans+=mp[tmp];
				}
			}
			mp.clear();
		}
	}
	cout<<ans;
	return 0;
}
